#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[1024];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) line[0] = '\0';
        line[strcspn(line, "\n")] = '\0';
        double sum = 0.0;
        int cnt = 0;
        char *token = strtok(line, " ");
        while (token) {
            sum += atof(token);
            ++cnt;
            token = strtok(NULL, " ");
        }
        double avg = cnt ? sum / cnt : 0.0;
        printf("%.2f\n", avg);
    }
    return 0;
}

