#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T + 1):
        line = data[i].strip() if i < len(data) else ''
        if not line:
            out_lines.append("0.00")
            continue
        nums = list(map(float, line.split()))
        avg = sum(nums) / len(nums) if nums else 0.0
        out_lines.append(f"{avg:.2f}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

